import{_ as i,o as e,c as o,a2 as t}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Contratos compatibilidad y evolucion","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/09-contratos-compatibilidad-y-evolucion.md","filePath":"full-stack/arquitectura/apis-rest/09-contratos-compatibilidad-y-evolucion.md","lastUpdated":1782521464000}'),l={name:"full-stack/arquitectura/apis-rest/09-contratos-compatibilidad-y-evolucion.md"};function n(s,a,c,r,d,p){return e(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="contratos-compatibilidad-y-evolucion" tabindex="-1">Contratos compatibilidad y evolucion <a class="header-anchor" href="#contratos-compatibilidad-y-evolucion" aria-label="Permalink to &quot;Contratos compatibilidad y evolucion&quot;">​</a></h1><p>Una API es un contrato. El codigo puede cambiar cada dia, pero el contrato debe evolucionar con cuidado.</p><h2 id="contrato-explicito" tabindex="-1">Contrato explicito <a class="header-anchor" href="#contrato-explicito" aria-label="Permalink to &quot;Contrato explicito&quot;">​</a></h2><p>El contrato incluye:</p><ul><li>Rutas.</li><li>Metodos.</li><li>Parametros.</li><li>Campos.</li><li>Tipos.</li><li>Codigos HTTP.</li><li>Codigos de error.</li><li>Reglas de autenticacion.</li><li>Garantias de paginacion.</li></ul><h2 id="consumer-driven-thinking" tabindex="-1">Consumer-driven thinking <a class="header-anchor" href="#consumer-driven-thinking" aria-label="Permalink to &quot;Consumer-driven thinking&quot;">​</a></h2><p>Disena pensando en quien consume:</p><ul><li>Frontend web.</li><li>App movil.</li><li>Integraciones externas.</li><li>Jobs internos.</li><li>Herramientas de reporting.</li></ul><p>Cada consumidor puede tener necesidades distintas.</p><h2 id="campos-opcionales" tabindex="-1">Campos opcionales <a class="header-anchor" href="#campos-opcionales" aria-label="Permalink to &quot;Campos opcionales&quot;">​</a></h2><p>Anadir campos suele ser compatible, pero solo si los clientes toleran campos desconocidos.</p><p>Recomendacion:</p><ul><li>Los clientes no deben fallar ante campos extra.</li><li>La API no debe eliminar campos sin deprecar.</li><li>Los enums deben documentar comportamiento ante valores nuevos.</li></ul><h2 id="compatibilidad-hacia-atras" tabindex="-1">Compatibilidad hacia atras <a class="header-anchor" href="#compatibilidad-hacia-atras" aria-label="Permalink to &quot;Compatibilidad hacia atras&quot;">​</a></h2><p>Antes de cambiar:</p><ol><li>Revisa clientes reales.</li><li>Mide uso del campo o endpoint.</li><li>Publica alternativa.</li><li>Depreca.</li><li>Elimina despues de la ventana acordada.</li></ol><h2 id="contract-testing" tabindex="-1">Contract testing <a class="header-anchor" href="#contract-testing" aria-label="Permalink to &quot;Contract testing&quot;">​</a></h2><p>Usa tests que detecten cambios incompatibles en OpenAPI:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main contract</span></span>
<span class="line"><span>  vs</span></span>
<span class="line"><span>pull request contract</span></span></code></pre></div><p>Si desaparece un campo obligatorio o cambia un tipo, la CI debe avisar.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>OpenAPI se trata como contrato.</li><li>Los cambios incompatibles se revisan.</li><li>Hay politica de deprecacion.</li><li>Los clientes toleran campos desconocidos.</li><li>Los errores tienen codigos estables.</li></ul>`,22)])])}const h=i(l,[["render",n]]);export{m as __pageData,h as default};
